    private string activeTab = "invoices";
    private List<VetClinic.Data.Invoice> invoices = [];
    private List<VetClinic.Data.Payment> payments = [];
    private List<VetClinic.Data.Appointment> completedAppointments = [];
    private bool showUnpaidOnly;
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private VetClinic.Data.Invoice? payingInvoice;
    private VetClinic.Data.Invoice? viewingInvoice;

    // Invoice creation
    private int selectedAppointmentId;
    private DateTime invoiceDueDate = DateTime.Today.AddDays(30);
    private string invoiceDescription = "";
    private List<VetClinic.Data.InvoiceLineItem> lineItems = [new()];
    private string? invoiceError;

    // Payment
    private decimal paymentAmount;
    private VetClinic.Data.PaymentMethod paymentMethod;
    private string? paymentReference;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoicesAsync();
        await LoadPaymentsAsync();
        await LoadCompletedAppointmentsAsync();
    }

    private async Task LoadInvoicesAsync()
    {
        invoices = await ClinicService.GetInvoicesAsync(showUnpaidOnly ? true : null);
    }

    private async Task LoadPaymentsAsync()
    {
        payments = await ClinicService.GetPaymentHistoryAsync();
    }

    private async Task LoadCompletedAppointmentsAsync()
    {
        var allApts = await ClinicService.GetAppointmentsAsync();
        completedAppointments = allApts.Where(a => a.Status == VetClinic.Data.AppointmentStatus.Completed && a.Invoice == null).ToList();
    }

    private async void ShowCreateInvoice()
    {
        activeTab = "create";
        showInvoiceForm = true;
        lineItems = [new()];
        selectedAppointmentId = 0;
        invoiceDescription = "";
        invoiceDueDate = DateTime.Today.AddDays(30);
        invoiceError = null;
        await LoadCompletedAppointmentsAsync();
        StateHasChanged();
    }

    private async Task CreateInvoice()
    {
        invoiceError = null;
        if (selectedAppointmentId == 0)
        {
            invoiceError = "Please select an appointment.";
            return;
        }
        if (!lineItems.Any(l => !string.IsNullOrWhiteSpace(l.Description)))
        {
            invoiceError = "Please add at least one line item.";
            return;
        }

        var validItems = lineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description)).ToList();
        var invoice = new VetClinic.Data.Invoice
        {
            AppointmentId = selectedAppointmentId,
            Description = invoiceDescription,
            DueDate = invoiceDueDate,
            TotalAmount = validItems.Sum(l => l.Quantity * l.UnitPrice),
            LineItems = validItems
        };

        await ClinicService.SaveInvoiceAsync(invoice);
        showInvoiceForm = false;
        activeTab = "invoices";
        await LoadInvoicesAsync();
        await LoadCompletedAppointmentsAsync();
    }

    private void ShowPayment(VetClinic.Data.Invoice invoice)
    {
        payingInvoice = invoice;
        paymentAmount = invoice.Balance;
        paymentMethod = VetClinic.Data.PaymentMethod.Cash;
        paymentReference = null;
        showPaymentForm = true;
    }

    private async Task ProcessPayment()
    {
        if (payingInvoice == null) return;

        var payment = new VetClinic.Data.Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference
        };

        await ClinicService.AddPaymentAsync(payment);
        showPaymentForm = false;
        await LoadInvoicesAsync();
        await LoadPaymentsAsync();
    }

    private async Task ViewInvoice(int id)
    {
        viewingInvoice = await ClinicService.GetInvoiceAsync(id);
    }
}
