        upcomingAppointments = (await ClinicService.GetAppointmentsAsync(now, now.AddDays(7)))
            .Where(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled).Take(5).ToList();

        recentPayments = (await ClinicService.GetPaymentHistoryAsync()).Take(5).ToList();
    }
