@code {
    private DateTime selectedDate = DateTime.Today;
    private List<VetClinic.Data.Appointment> appointments = [];
    private List<VetClinic.Data.Pet> allPets = [];
    private List<(DateTime Start, DateTime End)> availableSlots = [];
    private bool showForm;
    private VetClinic.Data.Appointment editingAppointment = new();
    private DateOnly appointmentDate = DateOnly.FromDateTime(DateTime.Today);
    private int selectedSlotIndex = -1;
    private string? formError;

    protected override async Task OnInitializedAsync()
    {
        allPets = await ClinicService.GetAllPetsAsync();
        await LoadAppointmentsAsync();
    }

    private async Task LoadAppointmentsAsync()
    {
        var start = selectedDate.Date;
        var end = start.AddDays(1);
        appointments = await ClinicService.GetAppointmentsAsync(start, end);
    }

    private async Task LoadAvailableSlots()
    {
        availableSlots = await ClinicService.GetAvailableSlotsAsync(appointmentDate);
        selectedSlotIndex = -1;
    }

    private async void ShowScheduleForm()
    {
        editingAppointment = new();
        appointmentDate = DateOnly.FromDateTime(selectedDate);
        await LoadAvailableSlots();
        showForm = true;
        formError = null;
        StateHasChanged();
    }

    private void CancelForm() { showForm = false; formError = null; }

    private async Task Reschedule(VetClinic.Data.Appointment apt)
    {
        editingAppointment = apt;
        appointmentDate = DateOnly.FromDateTime(apt.StartTime);
        await LoadAvailableSlots();
        showForm = true;
        formError = null;
    }

    private async Task Cancel(int id)
    {
        await ClinicService.CancelAppointmentAsync(id);
        await LoadAppointmentsAsync();
    }

    private async Task Complete(VetClinic.Data.Appointment apt)
    {
        apt.Status = VetClinic.Data.AppointmentStatus.Completed;
        await ClinicService.SaveAppointmentAsync(apt);
        await LoadAppointmentsAsync();
    }

    private async Task SaveAppointment()
    {
        formError = null;

        if (editingAppointment.PetId == 0)
        {
            formError = "Please select a pet.";
            return;
        }

        if (selectedSlotIndex < 0 || selectedSlotIndex >= availableSlots.Count)
        {
            formError = "Please select an available time slot.";
            return;
        }

        var slot = availableSlots[selectedSlotIndex];
        editingAppointment.StartTime = slot.Start;
        editingAppointment.EndTime = slot.End;

        var available = await ClinicService.IsTimeSlotAvailableAsync(slot.Start, slot.End, editingAppointment.Id == 0 ? null : editingAppointment.Id);
        if (!available)
        {
            formError = "This time slot is no longer available. Please select another.";
            await LoadAvailableSlots();
            return;
        }

        await ClinicService.SaveAppointmentAsync(editingAppointment);
        showForm = false;
        selectedDate = slot.Start.Date;
        await LoadAppointmentsAsync();
    }
}
