## 4. Update ApplicationDbContext

Edit `Data/ApplicationDbContext.cs` to add DbSets for all entities and configure relationships:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceLineItem> InvoiceLineItems => Set<InvoiceLineItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Owner>(e =>
        {
            e.HasMany(o => o.Pets).WithOne(p => p.Owner).HasForeignKey(p => p.OwnerId).OnDelete(DeleteBehavior.Cascade);
        });

        builder.Entity<Pet>(e =>
        {
            e.HasMany(p => p.TreatmentNotes).WithOne(t => t.Pet).HasForeignKey(t => t.PetId).OnDelete(DeleteBehavior.Cascade);
            e.HasMany(p => p.Appointments).WithOne(a => a.Pet).HasForeignKey(a => a.PetId).OnDelete(DeleteBehavior.Cascade);
        });

        builder.Entity<Appointment>(e =>
        {
            e.HasOne(a => a.Invoice).WithOne(i => i.Appointment).HasForeignKey<Invoice>(i => i.AppointmentId).OnDelete(DeleteBehavior.Cascade);
        });

        builder.Entity<Invoice>(e =>
        {
            e.HasMany(i => i.LineItems).WithOne(l => l.Invoice).HasForeignKey(l => l.InvoiceId).OnDelete(DeleteBehavior.Cascade);
            e.HasMany(i => i.Payments).WithOne(p => p.Invoice).HasForeignKey(p => p.InvoiceId).OnDelete(DeleteBehavior.Cascade);
            e.Property(i => i.TotalAmount).HasColumnType("decimal(18,2)");
            e.Property(i => i.AmountPaid).HasColumnType("decimal(18,2)");
        });

        builder.Entity<InvoiceLineItem>(e =>
        {
            e.Property(l => l.UnitPrice).HasColumnType("decimal(18,2)");
        });

        builder.Entity<Payment>(e =>
        {
            e.Property(p => p.Amount).HasColumnType("decimal(18,2)");
        });

        builder.Entity<Pet>(e =>
        {
            e.Property(p => p.WeightKg).HasColumnType("decimal(5,2)");
        });
    }
}
```

## 5. Create Services in `Data/` folder

Create `Data/ClinicService.cs` — a single scoped service that handles all data operations:

```csharp
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ClinicService(ApplicationDbContext db)
{
    // --- Owners ---
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Pets).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(o => o.FirstName.Contains(search) || o.LastName.Contains(search) || o.Pets.Any(p => p.Name.Contains(search)));
        return await query.OrderBy(o => o.LastName).ThenBy(o => o.FirstName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).ThenInclude(p => p.TreatmentNotes).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    public async Task DeleteOwnerAsync(int id)
    {
        var owner = await db.Owners.FindAsync(id);
        if (owner != null) { db.Owners.Remove(owner); await db.SaveChangesAsync(); }
    }

    // --- Pets ---
    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes.OrderByDescending(t => t.CreatedAt)).Include(p => p.Appointments.OrderByDescending(a => a.StartTime)).FirstOrDefaultAsync(p => p.Id == id);

    public async Task<List<Pet>> GetAllPetsAsync(string? search = null)
    {
        var query = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(p => p.Name.Contains(search) || p.Owner.LastName.Contains(search));
        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task SavePetAsync(Pet pet)
    {
        if (pet.Id == 0) db.Pets.Add(pet);
        else db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task DeletePetAsync(int id)
    {
        var pet = await db.Pets.FindAsync(id);
        if (pet != null) { db.Pets.Remove(pet); await db.SaveChangesAsync(); }
    }

    // --- Treatment Notes ---
    public async Task AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
    }

    public async Task DeleteTreatmentNoteAsync(int id)
    {
        var note = await db.TreatmentNotes.FindAsync(id);
        if (note != null) { db.TreatmentNotes.Remove(note); await db.SaveChangesAsync(); }
    }

    // --- Appointments ---
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        var query = db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue) query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue) query = query.Where(a => a.StartTime <= to.Value);
        return await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).Include(a => a.Invoice).ThenInclude(i => i!.Payments).FirstOrDefaultAsync(a => a.Id == id);

    public async Task<bool> IsTimeSlotAvailableAsync(DateTime start, DateTime end, int? excludeAppointmentId = null)
    {
        var query = db.Appointments.Where(a => a.Status != AppointmentStatus.Cancelled && a.StartTime < end && a.EndTime > start);
        if (excludeAppointmentId.HasValue)
            query = query.Where(a => a.Id != excludeAppointmentId.Value);
        return !await query.AnyAsync();
    }

    public async Task<List<(DateTime Start, DateTime End)>> GetAvailableSlotsAsync(DateOnly date)
    {
        var dayStart = date.ToDateTime(new TimeOnly(8, 0));
        var dayEnd = date.ToDateTime(new TimeOnly(18, 0));

        var existingAppointments = await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled && a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        var slots = new List<(DateTime, DateTime)>();
        var slotDuration = TimeSpan.FromMinutes(30);
        var current = dayStart;

        while (current + slotDuration <= dayEnd)
        {
            var slotEnd = current + slotDuration;
            if (!existingAppointments.Any(a => a.StartTime < slotEnd && a.EndTime > current))
                slots.Add((current, slotEnd));
            current = current.Add(slotDuration);
        }

        return slots;
    }

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var apt = await db.Appointments.FindAsync(id);
        if (apt != null) { apt.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
    }

    // --- Invoices ---
    public async Task<List<Invoice>> GetInvoicesAsync(bool? unpaidOnly = null)
    {
        var query = db.Invoices.Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner).Include(i => i.Payments).AsQueryable();
        if (unpaidOnly == true)
            query = query.Where(i => i.AmountPaid < i.TotalAmount);
        return await query.OrderByDescending(i => i.CreatedAt).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices.Include(i => i.LineItems).Include(i => i.Payments).Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner).FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0)
        {
            var count = await db.Invoices.CountAsync();
            invoice.InvoiceNumber = $"INV-{count + 1:D5}";
            db.Invoices.Add(invoice);
        }
        else
        {
            db.Invoices.Update(invoice);
        }
        await db.SaveChangesAsync();
    }

    public async Task AddPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.FindAsync(payment.InvoiceId);
        if (invoice != null) invoice.AmountPaid += payment.Amount;
        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync()
    {
        return await db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner).OrderByDescending(p => p.PaidAt).ToListAsync();
    }
}
```

