    private int todayCount;
    private int patientCount;
    private int unpaidCount;
    private List<VetClinic.Data.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Payment> recentPayments = [];

    protected override async Task OnInitializedAsync()
    {
        var now = DateTime.UtcNow;
        var todayStart = now.Date;
        var todayEnd = todayStart.AddDays(1);

        var todayApts = await ClinicService.GetAppointmentsAsync(todayStart, todayEnd);
        todayCount = todayApts.Count(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled);

        var allPets = await ClinicService.GetAllPetsAsync();
        patientCount = allPets.Count;

        var unpaid = await ClinicService.GetInvoicesAsync(unpaidOnly: true);
        unpaidCount = unpaid.Count;

        upcomingAppointments = (await ClinicService.GetAppointmentsAsync(now, now.AddDays(7)))
            .Where(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled).Take(5).ToList();

        recentPayments = (await ClinicService.GetPaymentHistoryAsync()).Take(5).ToList();
    }
}
