using System.ComponentModel.DataAnnotations;

namespace VetClinic.Data;

public class Owner
{
    public int Id { get; set; }

    [Required, MaxLength(100)]
    public string FirstName { get; set; } = string.Empty;

    [Required, MaxLength(100)]
    public string LastName { get; set; } = string.Empty;

    [Phone]
    public string? Phone { get; set; }

    [EmailAddress]
    public string? Email { get; set; }

    public string FullName => $"{FirstName} {LastName}";

    public List<Pet> Pets { get; set; } = [];
}

public class Pet
{
    public int Id { get; set; }

    [Required, MaxLength(100)]
    public string Name { get; set; } = string.Empty;

    [Required, MaxLength(50)]
    public string Species { get; set; } = string.Empty;

    [MaxLength(50)]
    public string? Breed { get; set; }

    public DateOnly? DateOfBirth { get; set; }

    public decimal? WeightKg { get; set; }

    [MaxLength(20)]
    public string? MicrochipId { get; set; }

    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;

    public List<TreatmentNote> TreatmentNotes { get; set; } = [];
    public List<Appointment> Appointments { get; set; } = [];
}

public class TreatmentNote
{
    public int Id { get; set; }

    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;

    [Required, MaxLength(200)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [MaxLength(100)]
    public string? Veterinarian { get; set; }

    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled
}

public class Appointment
{
    public int Id { get; set; }

    public DateTime StartTime { get; set; }

    public DateTime EndTime { get; set; }

    [Required, MaxLength(200)]
    public string Reason { get; set; } = string.Empty;

    [MaxLength(500)]
    public string? Notes { get; set; }

    public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;

    [MaxLength(100)]
    public string? Veterinarian { get; set; }

    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;

    public Invoice? Invoice { get; set; }
}

public class Invoice
{
    public int Id { get; set; }

    [Required, MaxLength(20)]
    public string InvoiceNumber { get; set; } = string.Empty;

    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;

    public DateTime? DueDate { get; set; }

    public decimal TotalAmount { get; set; }

    public decimal AmountPaid { get; set; }

    public decimal Balance => TotalAmount - AmountPaid;

    public bool IsPaid => Balance <= 0;

    [MaxLength(500)]
    public string? Description { get; set; }

    public int AppointmentId { get; set; }
    public Appointment Appointment { get; set; } = null!;

    public List<InvoiceLineItem> LineItems { get; set; } = [];
    public List<Payment> Payments { get; set; } = [];
}

public class InvoiceLineItem
{
    public int Id { get; set; }

    [Required, MaxLength(200)]
    public string Description { get; set; } = string.Empty;

    public int Quantity { get; set; } = 1;

    public decimal UnitPrice { get; set; }

    public decimal Total => Quantity * UnitPrice;

    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
}

public enum PaymentMethod
{
    Cash,
    CreditCard,
    DebitCard,
    BankTransfer,
    Check
}

public class Payment
{
    public int Id { get; set; }

    public DateTime PaidAt { get; set; } = DateTime.UtcNow;

    public decimal Amount { get; set; }

    public PaymentMethod Method { get; set; }

    [MaxLength(100)]
    public string? Reference { get; set; }

    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
}

using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ClinicService(ApplicationDbContext db)
{
    // --- Owners ---
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Pets).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(o => o.FirstName.Contains(search) || o.LastName.Contains(search) || o.Pets.Any(p => p.Name.Contains(search)));
        return await query.OrderBy(o => o.LastName).ThenBy(o => o.FirstName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).ThenInclude(p => p.TreatmentNotes).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    public async Task DeleteOwnerAsync(int id)
    {
        var owner = await db.Owners.FindAsync(id);
