@page "/"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ClinicService ClinicService

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-4">@todayCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Registered Patients</h5>
                <p class="card-text display-4">@patientCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Outstanding Invoices</h5>
                <p class="card-text display-4">@unpaidCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.StartTime.ToString("g")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Pet.Owner.FullName</td>
                            <td>@apt.Reason</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Payments</h4>
        @if (recentPayments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Pet</th></tr></thead>
                <tbody>
                    @foreach (var pay in recentPayments)
                    {
                        <tr>
                            <td>@pay.PaidAt.ToString("g")</td>
                            <td>@pay.Amount.ToString("C")</td>
                            <td>@pay.Method</td>
                            <td>@pay.Invoice.Appointment.Pet.Name</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent payments.</p>
        }
    </div>
</div>

@code {
    private int todayCount;
    private int patientCount;
    private int unpaidCount;
    private List<VetClinic.Data.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Payment> recentPayments = [];

    protected override async Task OnInitializedAsync()
    {
        var now = DateTime.UtcNow;
        var todayStart = now.Date;
        var todayEnd = todayStart.AddDays(1);

        var todayApts = await ClinicService.GetAppointmentsAsync(todayStart, todayEnd);
        todayCount = todayApts.Count(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled);

        var allPets = await ClinicService.GetAllPetsAsync();
        patientCount = allPets.Count;

        var unpaid = await ClinicService.GetInvoicesAsync(unpaidOnly: true);
        unpaidCount = unpaid.Count;

        upcomingAppointments = (await ClinicService.GetAppointmentsAsync(now, now.AddDays(7)))
            .Where(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled).Take(5).ToList();

        recentPayments = (await ClinicService.GetPaymentHistoryAsync()).Take(5).ToList();
    }
}

