                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => DeletePet(pet.Id)">Delete</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<VetClinic.Data.Pet> pets = [];
    private List<VetClinic.Data.Owner> owners = [];
    private string? searchTerm;
    private bool showOwnerForm;
    private bool showPetForm;
    private VetClinic.Data.Owner editingOwner = new();
    private VetClinic.Data.Pet editingPet = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        pets = await ClinicService.GetAllPetsAsync(searchTerm);
        owners = await ClinicService.GetOwnersAsync();
    }

    private async Task SearchAsync() => await LoadDataAsync();

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; showPetForm = false; }
    private void ShowAddPet() { editingPet = new(); showPetForm = true; showOwnerForm = false; }
    private void CancelOwnerForm() => showOwnerForm = false;
    private void CancelPetForm() => showPetForm = false;

    private void EditPet(VetClinic.Data.Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
        showOwnerForm = false;
    }

    private async Task SaveOwner()
    {
        await ClinicService.SaveOwnerAsync(editingOwner);
        showOwnerForm = false;
        await LoadDataAsync();
    }

    private async Task SavePet()
    {
        await ClinicService.SavePetAsync(editingPet);
        showPetForm = false;
        await LoadDataAsync();
    }

    private async Task DeletePet(int id)
    {
        await ClinicService.DeletePetAsync(id);
        await LoadDataAsync();
    }
}

