@inject VetClinic.Data.ClinicService ClinicService

<PageTitle>Appointments</PageTitle>

<h2>Appointment Scheduling</h2>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointmentsAsync" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowScheduleForm">+ Schedule Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "Schedule New Appointment" : "Reschedule Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in allPets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date</label>
                        <input type="date" class="form-control" @bind="appointmentDate" @bind:after="LoadAvailableSlots" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Available Slot</label>
                        <select class="form-control" @bind="selectedSlotIndex">
                            <option value="-1">-- Select --</option>
