<h4>@(selectedDate.ToString("D"))</h4>

@if (appointments.Any())
{
    <table class="table table-hover">
        <thead><tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>
            @foreach (var apt in appointments)
            {
                <tr class="@(apt.Status == VetClinic.Data.AppointmentStatus.Cancelled ? "table-secondary" : "")">
