                    <td>
                        @if (apt.Status == VetClinic.Data.AppointmentStatus.Scheduled)
                        {
                            <button class="btn btn-sm btn-outline-warning" @onclick="() => Reschedule(apt)">Reschedule</button>
                            <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => Cancel(apt.Id)">Cancel</button>
                            <button class="btn btn-sm btn-outline-success ms-1" @onclick="() => Complete(apt)">Complete</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
