@code {
    private DateTime selectedDate = DateTime.Today;
    private List<VetClinic.Data.Appointment> appointments = [];
    private List<VetClinic.Data.Pet> allPets = [];
    private List<(DateTime Start, DateTime End)> availableSlots = [];
    private bool showForm;
    private VetClinic.Data.Appointment editingAppointment = new();
    private DateOnly appointmentDate = DateOnly.FromDateTime(DateTime.Today);
    private int selectedSlotIndex = -1;
    private string? formError;

    protected override async Task OnInitializedAsync()
    {
        allPets = await ClinicService.GetAllPetsAsync();
        await LoadAppointmentsAsync();
    }

    private async Task LoadAppointmentsAsync()
    {
        var start = selectedDate.Date;
        var end = start.AddDays(1);
        appointments = await ClinicService.GetAppointmentsAsync(start, end);
    }

    private async Task LoadAvailableSlots()
    {
        availableSlots = await ClinicService.GetAvailableSlotsAsync(appointmentDate);
        selectedSlotIndex = -1;
    }

    private async void ShowScheduleForm()
    {
        editingAppointment = new();
        appointmentDate = DateOnly.FromDateTime(selectedDate);
        await LoadAvailableSlots();
        showForm = true;
        formError = null;
        StateHasChanged();
    }

    private void CancelForm() { showForm = false; formError = null; }

    private async Task Reschedule(VetClinic.Data.Appointment apt)
    {
        editingAppointment = apt;
        appointmentDate = DateOnly.FromDateTime(apt.StartTime);
        await LoadAvailableSlots();
        showForm = true;
        formError = null;
    }

    private async Task Cancel(int id)
    {
        await ClinicService.CancelAppointmentAsync(id);
        await LoadAppointmentsAsync();
    }

    private async Task Complete(VetClinic.Data.Appointment apt)
    {
        apt.Status = VetClinic.Data.AppointmentStatus.Completed;
        await ClinicService.SaveAppointmentAsync(apt);
        await LoadAppointmentsAsync();
    }

    private async Task SaveAppointment()
    {
        formError = null;

        if (editingAppointment.PetId == 0)
        {
            formError = "Please select a pet.";
            return;
        }

        if (selectedSlotIndex < 0 || selectedSlotIndex >= availableSlots.Count)
        {
            formError = "Please select an available time slot.";
            return;
        }

        var slot = availableSlots[selectedSlotIndex];
        editingAppointment.StartTime = slot.Start;
        editingAppointment.EndTime = slot.End;

        var available = await ClinicService.IsTimeSlotAvailableAsync(slot.Start, slot.End, editingAppointment.Id == 0 ? null : editingAppointment.Id);
        if (!available)
        {
            formError = "This time slot is no longer available. Please select another.";
            await LoadAvailableSlots();
            return;
        }

        await ClinicService.SaveAppointmentAsync(editingAppointment);
        showForm = false;
        selectedDate = slot.Start.Date;
        await LoadAppointmentsAsync();
    }
}

@page "/billing"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ClinicService ClinicService

<PageTitle>Billing</PageTitle>

<h2>Billing &amp; Payments</h2>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <a class="nav-link @(activeTab == "invoices" ? "active" : "")" href="#" @onclick="() => activeTab = &quot;invoices&quot;" @onclick:preventDefault>Invoices</a>
    </li>
    <li class="nav-item">
        <a class="nav-link @(activeTab == "payments" ? "active" : "")" href="#" @onclick="() => activeTab = &quot;payments&quot;" @onclick:preventDefault>Payment History</a>
    </li>
    <li class="nav-item">
        <a class="nav-link @(activeTab == "create" ? "active" : "")" href="#" @onclick="ShowCreateInvoice" @onclick:preventDefault>+ New Invoice</a>
    </li>
</ul>

@if (activeTab == "create" || showInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-header">Generate Invoice</div>
        <div class="card-body">
            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Appointment</label>
                    <select class="form-control" @bind="selectedAppointmentId">
                        <option value="0">-- Select completed appointment --</option>
                        @foreach (var apt in completedAppointments)
                        {
                            <option value="@apt.Id">@apt.StartTime.ToString("d") - @apt.Pet.Name (@apt.Reason)</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="invoiceDueDate" />
                </div>
                <div class="col-md-5">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="invoiceDescription" />
                </div>
            </div>

            <h6>Line Items</h6>
            @for (var i = 0; i < lineItems.Count; i++)
            {
                var idx = i;
                <div class="row mb-1">
                    <div class="col-md-5">
                        <input type="text" class="form-control form-control-sm" placeholder="Description" @bind="lineItems[idx].Description" />
                    </div>
                    <div class="col-md-2">
                        <input type="number" class="form-control form-control-sm" placeholder="Qty" @bind="lineItems[idx].Quantity" />
                    </div>
                    <div class="col-md-2">
                        <input type="number" class="form-control form-control-sm" step="0.01" placeholder="Unit Price" @bind="lineItems[idx].UnitPrice" />
                    </div>
                    <div class="col-md-2">
                        <span class="form-control-plaintext">@((lineItems[idx].Quantity * lineItems[idx].UnitPrice).ToString("C"))</span>
                    </div>
                    <div class="col-md-1">
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => lineItems.RemoveAt(idx)">×</button>
                    </div>
                </div>
            }
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => lineItems.Add(new())">+ Add Line</button>

            <div class="mt-2"><strong>Total: @lineItems.Sum(l => l.Quantity * l.UnitPrice).ToString("C")</strong></div>

            @if (!string.IsNullOrEmpty(invoiceError))
            {
                <div class="alert alert-danger mt-2">@invoiceError</div>
            }
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="CreateInvoice">Generate Invoice</button>
                <button class="btn btn-secondary ms-2" @onclick="CancelInvoiceForm">Cancel</button>
            </div>
        </div>
    </div>
}

@if (activeTab == "invoices")
{
    <div class="mb-2">
        <div class="form-check form-check-inline">
            <input class="form-check-input" type="checkbox" @bind="showUnpaidOnly" @bind:after="LoadInvoicesAsync" id="unpaidFilter" />
            <label class="form-check-label" for="unpaidFilter">Show unpaid only</label>
        </div>
    </div>

    <table class="table table-hover">
        <thead><tr><th>Invoice #</th><th>Date</th><th>Pet</th><th>Owner</th><th>Total</th><th>Paid</th><th>Balance</th><th>Actions</th></tr></thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr class="@(inv.IsPaid ? "table-success" : "")">
                    <td>@inv.InvoiceNumber</td>
                    <td>@inv.CreatedAt.ToString("d")</td>
                    <td>@inv.Appointment.Pet.Name</td>
                    <td>@inv.Appointment.Pet.Owner.FullName</td>
                    <td>@inv.TotalAmount.ToString("C")</td>
                    <td>@inv.AmountPaid.ToString("C")</td>
                    <td>@inv.Balance.ToString("C")</td>
                    <td>
                        @if (!inv.IsPaid)
                        {
                            <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPayment(inv)">Record Payment</button>
                        }
                        <button class="btn btn-sm btn-outline-info ms-1" @onclick="() => ViewInvoice(inv.Id)">View</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (activeTab == "payments")
{
    <table class="table table-hover">
        <thead><tr><th>Date</th><th>Invoice</th><th>Pet</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
        <tbody>
            @foreach (var pay in payments)
            {
                <tr>
                    <td>@pay.PaidAt.ToString("g")</td>
                    <td>@pay.Invoice.InvoiceNumber</td>
                    <td>@pay.Invoice.Appointment.Pet.Name</td>
                    <td>@pay.Amount.ToString("C")</td>
                    <td>@pay.Method</td>
                    <td>@(pay.Reference ?? "—")</td>
                </tr>
            }
        </tbody>
    </table>
}

@if (showPaymentForm)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5);">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Record Payment — @payingInvoice?.InvoiceNumber</h5>
                    <button type="button" class="btn-close" @onclick="() => showPaymentForm = false"></button>
                </div>
                <div class="modal-body">
                    <div class="mb-2">
                        <label class="form-label">Amount (Balance: @payingInvoice?.Balance.ToString("C"))</label>
                        <input type="number" step="0.01" class="form-control" @bind="paymentAmount" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Payment Method</label>
                        <select class="form-control" @bind="paymentMethod">
                            @foreach (var method in Enum.GetValues<VetClinic.Data.PaymentMethod>())
                            {
                                <option value="@method">@method</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reference</label>
                        <input type="text" class="form-control" @bind="paymentReference" />
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-success" @onclick="ProcessPayment">Process Payment</button>
                    <button class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (viewingInvoice != null)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Invoice @viewingInvoice.InvoiceNumber</h5>
                    <button type="button" class="btn-close" @onclick="() => viewingInvoice = null"></button>
                </div>
                <div class="modal-body">
                    <p><strong>Pet:</strong> @viewingInvoice.Appointment.Pet.Name | <strong>Owner:</strong> @viewingInvoice.Appointment.Pet.Owner.FullName</p>
                    <p><strong>Date:</strong> @viewingInvoice.CreatedAt.ToString("d") | <strong>Due:</strong> @(viewingInvoice.DueDate?.ToString("d") ?? "N/A")</p>
                    @if (!string.IsNullOrEmpty(viewingInvoice.Description))
                    {
                        <p>@viewingInvoice.Description</p>
                    }
                    <table class="table table-sm">
                        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th></tr></thead>
                        <tbody>
                            @foreach (var item in viewingInvoice.LineItems)
                            {
                                <tr><td>@item.Description</td><td>@item.Quantity</td><td>@item.UnitPrice.ToString("C")</td><td>@item.Total.ToString("C")</td></tr>
                            }
                        </tbody>
                        <tfoot><tr><td colspan="3" class="text-end"><strong>Total</strong></td><td><strong>@viewingInvoice.TotalAmount.ToString("C")</strong></td></tr></tfoot>
                    </table>
                    @if (viewingInvoice.Payments.Any())
                    {
                        <h6>Payments</h6>
                        <table class="table table-sm">
                            <thead><tr><th>Date</th><th>Amount</th><th>Method</th></tr></thead>
                            <tbody>
                                @foreach (var p in viewingInvoice.Payments)
                                {
                                    <tr><td>@p.PaidAt.ToString("g")</td><td>@p.Amount.ToString("C")</td><td>@p.Method</td></tr>
                                }
                            </tbody>
                        </table>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => viewingInvoice = null">Close</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private List<VetClinic.Data.Invoice> invoices = [];
    private List<VetClinic.Data.Payment> payments = [];
    private List<VetClinic.Data.Appointment> completedAppointments = [];
    private bool showUnpaidOnly;
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private VetClinic.Data.Invoice? payingInvoice;
    private VetClinic.Data.Invoice? viewingInvoice;

    // Invoice creation
    private int selectedAppointmentId;
    private DateTime invoiceDueDate = DateTime.Today.AddDays(30);
    private string invoiceDescription = "";
    private List<VetClinic.Data.InvoiceLineItem> lineItems = [new()];
    private string? invoiceError;

    // Payment
    private decimal paymentAmount;
    private VetClinic.Data.PaymentMethod paymentMethod;
    private string? paymentReference;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoicesAsync();
        await LoadPaymentsAsync();
        await LoadCompletedAppointmentsAsync();
    }

    private async Task LoadInvoicesAsync()
    {
        invoices = await ClinicService.GetInvoicesAsync(showUnpaidOnly ? true : null);
    }

    private async Task LoadPaymentsAsync()
    {
        payments = await ClinicService.GetPaymentHistoryAsync();
    }

    private async Task LoadCompletedAppointmentsAsync()
    {
        var allApts = await ClinicService.GetAppointmentsAsync();
        completedAppointments = allApts.Where(a => a.Status == VetClinic.Data.AppointmentStatus.Completed && a.Invoice == null).ToList();
    }

    private async void ShowCreateInvoice()
    {
        activeTab = "create";
        showInvoiceForm = true;
        lineItems = [new()];
        selectedAppointmentId = 0;
        invoiceDescription = "";
        invoiceDueDate = DateTime.Today.AddDays(30);
        invoiceError = null;
        await LoadCompletedAppointmentsAsync();
        StateHasChanged();
    }

    private void CancelInvoiceForm()
    {
        showInvoiceForm = false;
        activeTab = "invoices";
    }

    private async Task CreateInvoice()
    {
        invoiceError = null;
        if (selectedAppointmentId == 0)
        {
            invoiceError = "Please select an appointment.";
            return;
        }
        if (!lineItems.Any(l => !string.IsNullOrWhiteSpace(l.Description)))
        {
            invoiceError = "Please add at least one line item.";
            return;
        }

        var validItems = lineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description)).ToList();
        var invoice = new VetClinic.Data.Invoice
        {
            AppointmentId = selectedAppointmentId,
            Description = invoiceDescription,
            DueDate = invoiceDueDate,
            TotalAmount = validItems.Sum(l => l.Quantity * l.UnitPrice),
            LineItems = validItems
        };

        await ClinicService.SaveInvoiceAsync(invoice);
        showInvoiceForm = false;
        activeTab = "invoices";
        await LoadInvoicesAsync();
        await LoadCompletedAppointmentsAsync();
    }

    private void ShowPayment(VetClinic.Data.Invoice invoice)
    {
        payingInvoice = invoice;
        paymentAmount = invoice.Balance;
        paymentMethod = VetClinic.Data.PaymentMethod.Cash;
        paymentReference = null;
        showPaymentForm = true;
    }

    private async Task ProcessPayment()
    {
        if (payingInvoice == null) return;

        var payment = new VetClinic.Data.Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference
        };

        await ClinicService.AddPaymentAsync(payment);
        showPaymentForm = false;
        await LoadInvoicesAsync();
        await LoadPaymentsAsync();
    }

    private async Task ViewInvoice(int id)
    {
        viewingInvoice = await ClinicService.GetInvoiceAsync(id);
    }
}

